   170	  const headers: Record<string, string> = {
   171	    'Content-Type': 'application/json',
   172	    ...(options.headers as Record<string, string>),
   173	  };
   174	
   175	  // Add CSRF token for state-changing requests
   176	  const method = options.method?.toUpperCase() || 'GET';
   177	  if (['POST', 'PUT', 'PATCH', 'DELETE'].includes(method)) {
   178	    const token = await ensureCsrfToken();
   179	    headers['X-CSRF-Token'] = token;
   180	  }
   181	
   182	  const response = await fetch(`${API_URL}${endpoint}`, {
   183	    ...options,
   184	    credentials: 'include',
   185	    headers,
   186	  });
   187	
   188	  // CloudFront may intercept errors and return HTML - detect and redirect
   189	  if (!isJsonResponse(response)) {
   190	    // On public routes like /invite, return error response instead of redirecting
   191	    if (window.location.pathname.startsWith('/invite')) {
   192	      return {
   193	        success: false,
   194	        error: { code: 'NETWORK_ERROR', message: 'Server returned non-JSON response' },
   195	      } as ApiResponse<T>;
   196	    }
   197	    handleSessionExpired(); // never returns
   198	  }
   199	
   200	  const data: ApiResponse<T> = await response.json();
   201	
   202	  // Handle session expiration - redirect to login with expired=true
   203	  // Only for SESSION_EXPIRED (actual expiration), not UNAUTHORIZED (no session existed)
   204	  // Skip for public routes like /invite where 401 is expected for unauthenticated users
   205	  if (response.status === 401) {
   206	    if (data.error?.code === 'SESSION_EXPIRED') {
   207	      if (!window.location.pathname.startsWith('/invite')) {
   208	        handleSessionExpired(); // never returns - shows "session expired" message
   209	      }
   210	    }
   211	    // UNAUTHORIZED (no session) just returns error - ProtectedRoute will redirect without expired message
   212	    return data;
   213	  }
   214	
   215	  // If CSRF token is invalid, clear and retry once
   216	  if (response.status === 403 && data.error?.code === 'CSRF_ERROR') {
   217	    clearCsrfToken();
   218	    const newToken = await ensureCsrfToken();
   219	    headers['X-CSRF-Token'] = newToken;
   220	    const retryResponse = await fetch(`${API_URL}${endpoint}`, {
   221	      ...options,
   222	      credentials: 'include',
   223	      headers,
   224	    });
   225	    if (!isJsonResponse(retryResponse)) {
   226	      handleSessionExpired(); // never returns
   227	    }
   228	    return retryResponse.json();
   229	  }
   230	
   231	  return data;
   232	}
