    11	
    12	// Announcements happen at these seconds remaining
    13	const ANNOUNCEMENT_THRESHOLDS = [30, 20, 10, 5];
    14	
    15	export function SessionTimeoutModal({
    16	  open,
    17	  timeRemaining,
    18	  warningType,
    19	  onStayLoggedIn,
    20	}: SessionTimeoutModalProps) {
    21	  const stayLoggedInButtonRef = useRef<HTMLButtonElement>(null);
    22	  const [lastAnnouncement, setLastAnnouncement] = useState<number | null>(null);
    23	  const announcementRef = useRef<HTMLDivElement>(null);
    24	
    25	  // Format time as M:SS
    26	  const formatTime = (seconds: number): string => {
    27	    const mins = Math.floor(seconds / 60);
    28	    const secs = seconds % 60;
    29	    return `${mins}:${secs.toString().padStart(2, '0')}`;
    30	  };
    31	
    32	  // Focus the Stay Logged In button when modal opens
    33	  useEffect(() => {
    34	    if (open && stayLoggedInButtonRef.current) {
    35	      // Delay to ensure the modal is fully mounted
    36	      const timer = setTimeout(() => {
    37	        stayLoggedInButtonRef.current?.focus();
    38	      }, 50);
    39	      return () => clearTimeout(timer);
    40	    }
    41	  }, [open]);
    42	
    43	  // Screen reader announcements at key intervals
    44	  useEffect(() => {
    45	    if (!open || timeRemaining === null) return;
    46	
    47	    // Check if we should announce
    48	    if (
    49	      ANNOUNCEMENT_THRESHOLDS.includes(timeRemaining) &&
    50	      timeRemaining !== lastAnnouncement
    51	    ) {
    52	      setLastAnnouncement(timeRemaining);
    53	      // The aria-live region will automatically announce
    54	    }
    55	  }, [open, timeRemaining, lastAnnouncement]);
    56	
    57	  // Reset announcement tracking when modal closes
    58	  useEffect(() => {
    59	    if (!open) {
    60	      setLastAnnouncement(null);
    61	    }
    62	  }, [open]);
    63	
    64	  // Handle any user activity to dismiss modal (for inactivity warning only)
    65	  const handleActivity = useCallback(() => {
    66	    if (warningType === 'inactivity') {
    67	      onStayLoggedIn();
    68	    }
    69	  }, [warningType, onStayLoggedIn]);
    70	
    71	  // Handle keyboard events including focus trap
    72	  const handleKeyDown = useCallback(
    73	    (e: React.KeyboardEvent) => {
    74	      if (e.key === 'Escape' && warningType === 'inactivity') {
    75	        e.preventDefault();
    76	        onStayLoggedIn();
    77	      }
    78	
    79	      // Focus trap: keep Tab within modal
    80	      if (e.key === 'Tab') {
    81	        const focusableElements = e.currentTarget.querySelectorAll<HTMLElement>(
    82	          'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
    83	        );
    84	        const firstFocusable = focusableElements[0];
    85	        const lastFocusable = focusableElements[focusableElements.length - 1];
    86	
    87	        if (e.shiftKey && document.activeElement === firstFocusable) {
    88	          e.preventDefault();
    89	          lastFocusable?.focus();
    90	        } else if (!e.shiftKey && document.activeElement === lastFocusable) {
    91	          e.preventDefault();
    92	          firstFocusable?.focus();
    93	        }
    94	      }
    95	    },
    96	    [warningType, onStayLoggedIn]
    97	  );
    98	
    99	  const isInactivity = warningType === 'inactivity';
   100	  const title = isInactivity
   101	    ? 'Your session is about to expire'
   102	    : 'Your session will end soon';
   103	
   104	  const description = isInactivity
   105	    ? 'Due to inactivity, you will be logged out automatically. Move your mouse or press any key to stay logged in.'
   106	    : 'For security, your session will end in 5 minutes. Please save your work and log in again to continue.';
   107	
   108	  const buttonText = isInactivity ? 'Stay Logged In' : 'I Understand';
   109	
   110	  // Generate announcement text
   111	  const getAnnouncementText = (): string => {
   112	    if (timeRemaining === null) return '';
   113	
   114	    if (isInactivity) {
   115	      return `${timeRemaining} seconds until automatic logout. Move or click to stay logged in.`;
   116	    } else {
   117	      return `${timeRemaining} seconds until session ends. Please save your work.`;
   118	    }
   119	  };
   120	
   121	  return (
   122	    <Dialog.Root open={open}>
   123	      <Dialog.Portal>
   124	        <Dialog.Overlay
   125	          className="fixed inset-0 z-[100] bg-black/60"
   126	          onClick={handleActivity}
   127	          onMouseMove={handleActivity}
   128	        />
   129	        <Dialog.Content
   130	          role="alertdialog"
   131	          aria-modal="true"
   132	          aria-labelledby="session-timeout-title"
   133	          aria-describedby="session-timeout-description"
   134	          className="fixed left-1/2 top-1/2 z-[101] w-full max-w-md -translate-x-1/2 -translate-y-1/2 rounded-lg border border-border bg-background p-6 shadow-xl focus:outline-none"
   135	          onKeyDown={handleKeyDown}
   136	          onMouseMove={handleActivity}
   137	        >
   138	          {/* Screen reader announcement region */}
   139	          <div
   140	            ref={announcementRef}
   141	            role="status"
   142	            aria-live="assertive"
   143	            aria-atomic="true"
   144	            className="sr-only"
   145	          >
   146	            {ANNOUNCEMENT_THRESHOLDS.includes(timeRemaining ?? -1)
   147	              ? getAnnouncementText()
   148	              : ''}
   149	          </div>
   150	
   151	          <Dialog.Title
   152	            id="session-timeout-title"
   153	            className="text-lg font-semibold text-foreground"
   154	          >
   155	            {title}
   156	          </Dialog.Title>
   157	
   158	          <Dialog.Description
   159	            id="session-timeout-description"
   160	            className="mt-2 text-sm text-muted"
   161	          >
   162	            {description}
   163	          </Dialog.Description>
   164	
   165	          {/* Countdown Timer */}
   166	          <div className="mt-6 flex flex-col items-center">
   167	            <div
   168	              role="timer"
   169	              aria-label={`Time remaining: ${timeRemaining !== null ? formatTime(timeRemaining) : '0:00'}`}
   170	              className="text-5xl font-bold tabular-nums text-foreground"
   171	            >
   172	              {timeRemaining !== null ? formatTime(timeRemaining) : '0:00'}
   173	            </div>
   174	            <p className="mt-2 text-sm text-muted">
   175	              {isInactivity ? 'until automatic logout' : 'until session ends'}
   176	            </p>
   177	          </div>
   178	
   179	          {/* Action Button */}
   180	          <div className="mt-6 flex justify-center">
   181	            <button
   182	              ref={stayLoggedInButtonRef}
   183	              onClick={onStayLoggedIn}
   184	              className="rounded-md bg-accent px-6 py-3 text-base font-medium text-white hover:bg-accent/90 focus:outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2 focus:ring-offset-background"
   185	            >
   186	              {buttonText}
   187	            </button>
   188	          </div>
   189	
   190	          {/* Additional info for absolute timeout */}
   191	          {!isInactivity && (
   192	            <p className="mt-4 text-center text-xs text-muted">
   193	              This timeout cannot be extended. Please log in again after your
   194	              session ends.
   195	            </p>
   196	          )}
   197	        </Dialog.Content>
   198	      </Dialog.Portal>
   199	    </Dialog.Root>
   200	  );
   201	}
